using Payments;

namespace Payments.Tests;

[TestClass]
public class PaymentGatewayTests
{
    private PaymentGateway _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new PaymentGateway();
    }

    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    //  ChargeAsync вҖ“ valid inputs (NotImplementedException expected)
    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    public async Task ChargeAsync_ValidCardTokenAndPositiveAmount_ThrowsNotImplementedException()
    {
        // Arrange
        var cardToken = "tok_valid_123";
        var amount = 49.99m;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken, amount));
    }

    [TestMethod]
    public async Task ChargeAsync_LargeAmount_ThrowsNotImplementedException()
    {
        // Arrange
        var cardToken = "tok_large";
        var amount = 999_999.99m;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken, amount));
    }

    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    //  ChargeAsync вҖ“ zero & negative amounts
    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ThrowsNotImplementedException()
    {
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync("tok_zero", 0m));
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ThrowsNotImplementedException()
    {
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync("tok_negative", -10.00m));
    }

    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    //  ChargeAsync вҖ“ null / empty card token (parameterized)
    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    [DataRow(null, DisplayName = "ChargeAsync_NullCardToken_ThrowsNotImplementedException")]
    [DataRow("", DisplayName = "ChargeAsync_EmptyCardToken_ThrowsNotImplementedException")]
    [DataRow("   ", DisplayName = "ChargeAsync_WhitespaceCardToken_ThrowsNotImplementedException")]
    public async Task ChargeAsync_InvalidCardToken_ThrowsNotImplementedException(string? cardToken)
    {
        // Arrange
        var amount = 25.00m;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken!, amount));
    }

    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    //  ChargeAsync вҖ“ parameterized amounts via DataRow
    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    [DataRow(0.01, DisplayName = "ChargeAsync_SmallestPositiveAmount")]
    [DataRow(100.00, DisplayName = "ChargeAsync_RoundHundred")]
    [DataRow(0.00, DisplayName = "ChargeAsync_ExactZero")]
    [DataRow(-1.00, DisplayName = "ChargeAsync_NegativeOne")]
    public async Task ChargeAsync_VariousAmounts_ThrowsNotImplementedException(double amountDouble)
    {
        // DataRow does not support decimal literals, so we convert from double
        var amount = (decimal)amountDouble;

        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync("tok_param", amount));
    }

    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    //  RefundAsync вҖ“ valid input
    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ThrowsNotImplementedException()
    {
        // Arrange
        var chargeId = "ch_abc123";

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.RefundAsync(chargeId));
    }

    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    //  RefundAsync вҖ“ null / empty charge ID (parameterized)
    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    [DataRow(null, DisplayName = "RefundAsync_NullChargeId_ThrowsNotImplementedException")]
    [DataRow("", DisplayName = "RefundAsync_EmptyChargeId_ThrowsNotImplementedException")]
    [DataRow("   ", DisplayName = "RefundAsync_WhitespaceChargeId_ThrowsNotImplementedException")]
    public async Task RefundAsync_InvalidChargeId_ThrowsNotImplementedException(string? chargeId)
    {
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.RefundAsync(chargeId!));
    }

    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    //  RefundAsync вҖ“ various valid charge IDs (parameterized)
    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    [DataRow("ch_1", DisplayName = "RefundAsync_ShortChargeId")]
    [DataRow("ch_abcdef1234567890", DisplayName = "RefundAsync_LongChargeId")]
    [DataRow("charge-with-dashes", DisplayName = "RefundAsync_DashedChargeId")]
    public async Task RefundAsync_VariousChargeIds_ThrowsNotImplementedException(string chargeId)
    {
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.RefundAsync(chargeId));
    }

    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    //  Record type sanity checks
    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    public void ChargeResult_CanBeConstructed_WithExpectedProperties()
    {
        // Arrange & Act
        var result = new ChargeResult("ch_test", true);

        // Assert
        Assert.AreEqual("ch_test", result.ChargeId);
        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public void ChargeResult_FailureScenario_SuccessIsFalse()
    {
        var result = new ChargeResult("ch_fail", false);

        Assert.AreEqual("ch_fail", result.ChargeId);
        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public void RefundResult_CanBeConstructed_WithExpectedProperties()
    {
        var result = new RefundResult("rf_test", true);

        Assert.AreEqual("rf_test", result.RefundId);
        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public void RefundResult_FailureScenario_SuccessIsFalse()
    {
        var result = new RefundResult("rf_fail", false);

        Assert.AreEqual("rf_fail", result.RefundId);
        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public void ChargeResult_Equality_SameValues_AreEqual()
    {
        var a = new ChargeResult("ch_eq", true);
        var b = new ChargeResult("ch_eq", true);

        Assert.AreEqual(a, b);
    }

    [TestMethod]
    public void RefundResult_Equality_DifferentValues_AreNotEqual()
    {
        var a = new RefundResult("rf_1", true);
        var b = new RefundResult("rf_2", false);

        Assert.AreNotEqual(a, b);
    }
}

